            if all(p[i][j] < alpha for i in range(m)):
                return False
        # Check some shop covers >= 2 friends
        for i in range(m):
            count = sum(1 for j in range(n) if p[i][j] >= alpha)
            if count >= 2:
                return True
        return False

    lo, hi = 0, len(vals) - 1
    ans = 0
    while lo <= hi:
        mid = (lo + hi) // 2
        alpha = vals[mid]
        if feasible2(alpha):
            ans = alpha
